sql:
SELECT AVG(item_value) AS average_cost
FROM items
WHERE item_name = 'Warhammer';

SELECT 
    (SELECT AVG(item_value) FROM items) AS avg_item_value,
    (SELECT AVG(resource_value) FROM resources) AS avg_resource_value;

SELECT items.item_name
FROM items
INNER JOIN royal_permits ON items.item_id = royal_permits.item_id;

SELECT DISTINCT i.item_id, i.item_name
FROM items i
JOIN royal_permits rp ON i.item_id = rp.item_id;

SELECT COUNT(DISTINCT item_id)
FROM items
WHERE item_type = 'weapon' AND item_tier = 'rare';

SELECT i.item_name, e.enchantment_name, e.enchantment_effect
FROM items i
JOIN enchantments e ON i.item_id = e.item_id
WHERE i.item_rarity = (
    SELECT MAX(item_rarity) FROM items
);

SELECT AVG(value) AS average_value
FROM (
  SELECT item_value AS value FROM items
  UNION ALL
  SELECT resource_value AS value FROM resources
);

SELECT 
    (SELECT AVG(item_value) FROM items) AS average_item_value,
    (SELECT AVG(resource_value) FROM resources) AS average_resource_value;
